import sys
sys.setrecursionlimit(1000000)

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    H = int(data[0])
    W = int(data[1])
    grid = data[2:2+H]

    visited = [[False for _ in range(W)] for _ in range(H)]
    result = 0

    def dfs(x, y):
        if x < 0 or x >= H or y < 0 or y >= W or not grid[x][y] == '#' or visited[x][y]:
            return
        visited[x][y] = True
        for dx in [-1, 0, 1]:
            for dy in [-1, 0, 1]:
                if dx == 0 and dy == 0:
                    continue
                nx, ny = x + dx, y + dy
                dfs(nx, ny)

    for i in range(H):
        for j in range(W):
            if grid[i][j] == '#' and not visited[i][j]:
                dfs(i, j)
                result += 1
    print(result)

if __name__ == "__main__":
    main()
